    comms:{client_chattiness:40,client_chattiness_label:'Low-moderate',last_client_message:'2 months ago',off_channel_indicator:false,open_commitments:2,open_commitments_detail:['Aditya: schedule proactive check-in post March 3 call','Share planning deliverables that demonstrate visible progress to couple']},
    vendor_coverage:[{vendor_type:'Venue',status:'confirmed',note:'Sterling Aravalli, Udaipur — Feb 2-3, 2027'},{vendor_type:'Decor',status:'unassigned',note:'Not yet discussed'}],
    decision_intel:{velocity:'moderate',velocity_note:'Manan handles scheduling; Radhika is detail-oriented and expects structured communication',decision_makers:[{name:'Radhika',role:'Bride',authority:'Primary POC, holds team accountable for communication'},{name:'Manan',role:'Groom',authority:'Scheduling and logistics'}]},
