    messages:[{sender:'~ Radhika Thakkar',role:'Bride',initials:'RT',color:'#8B5CF6',bg:'rgba(139,92,246,0.15)',time:'Feb 28',body:'We are still waiting to hear from you regarding next steps. We were pushed to make payments to both Meragi and the property, and now that those are completed, we haven\'t seen any visible progress.',negative:true},{sender:'Aditya Sharma',role:'Planner',initials:'AS',color:'#F59E0B',bg:'rgba(245,158,11,0.15)',time:'Feb 28',body:'Hello Manan & Radhika — Aditya this side from Meragi. I\'ll be the planner for your wedding. I\'m sorry for the communication gap. Looking forward to connecting on Monday.',negative:false}],
